# ------------------------------------------------------------------------------
target_crs <- 32638
profile    <- "motorcar"

# UPDATE THESE PATHS IF NECESSARY
pbf_file  <- "C:/Users/Tshih/OneDrive/Distance between dental clinics and metro and bus stations/Data/gcc-states-251211.osm.pbf"
out_rds_w <- "C:/Users/Tshih/OneDrive/Distance between dental clinics and metro and bus stations/Data/graph_w_motorcar_clipped_OPTION1_directed.rds"

# ------------------------------------------------------------------------------
# 3. DATA PREP (Graph + Roads)
# ------------------------------------------------------------------------------
if(!exists("graph_w") || !exists("roads_sf")) {
  message("🔄 Loading/Building Graph Data...")
  
  # A. Define Boundary (Assume 'gisdata' and 'all2' exist in environment)
  clinics <- gisdata |> st_as_sf() |> st_transform(target_crs)
  stops <- all2 |> st_as_sf() |>
    mutate(type = tolower(trimws(type))) |>
    filter(type %in% c("bus stop","metro station")) |>
    st_transform(target_crs)
  
  combined_geoms <- c(st_geometry(clinics), st_geometry(stops))
  boundary <- st_union(combined_geoms) |> st_convex_hull() |> st_buffer(10000) |> st_make_valid()
  boundary_ll <- st_transform(boundary, 4326)
  
  # B. Read/Build Graph
  if(file.exists(out_rds_w)) {
    graph_w <- readRDS(out_rds_w)
    message("    Loaded graph_w from RDS.")
  } else {
    message("    Reading OSM PBF (this may take a moment)...")
    osm_lines_ll <- oe_read(
      pbf_file, layer = "lines", boundary = boundary_ll, boundary_type = "spat",
      extra_tags = "oneway", quiet = TRUE
    )
    roads_ll <- osm_lines_ll |>
      filter(!is.na(highway)) |>
      mutate(highway = sub(";.*$", "", tolower(highway)), oneway = tolower(oneway)) |>
      filter(highway %in% c("motorway","motorway_link","trunk","trunk_link",
                            "primary","primary_link","secondary","secondary_link",
                            "tertiary","tertiary_link","residential","unclassified",
                            "service","living_street","road")) |>
      st_cast("LINESTRING", warn = FALSE)
    
    graph_w <- dodgr::weight_streetnet(roads_ll, wt_profile = profile)
    saveRDS(graph_w, out_rds_w)
  }
  
  # C. Build roads_sf
  message("    Building roads_sf...")
  gw_df <- tibble::as_tibble(graph_w)
  roads_df <- gw_df %>% transmute(
    from_id = as.character(from_id), to_id = as.character(to_id),
    from_lon = as.numeric(from_lon), from_lat = as.numeric(from_lat),
    to_lon = as.numeric(to_lon), to_lat = as.numeric(to_lat),
    highway = as.character(highway)
  )
  geom_sfc <- mapply(function(x1, y1, x2, y2) {
    sf::st_linestring(matrix(c(x1, y1, x2, y2), ncol = 2, byrow = TRUE))
  }, roads_df$from_lon, roads_df$from_lat, roads_df$to_lon, roads_df$to_lat, SIMPLIFY = FALSE) |>
    sf::st_sfc(crs = 4326)
  
  roads_sf <- sf::st_sf(roads_df, geometry = geom_sfc) |> st_transform(target_crs)
  roads_sf$edge_len_m <- as.numeric(sf::st_length(roads_sf))
  
  message("✅ Data Preparation Complete.")
}

# ------------------------------------------------------------------------------
# 4. HELPER FUNCTIONS
# ------------------------------------------------------------------------------
orient_edge_geom_to_from <- function(e) {
  g <- sf::st_geometry(e)[[1]]; xy <- sf::st_coordinates(g)[, 1:2]
  A <- xy[1, ]; B <- xy[nrow(xy), ]
  from_pt <- sf::st_as_sf(data.frame(lon=e$from_lon[1], lat=e$from_lat[1]), coords=c("lon","lat"), crs=4326) |> sf::st_transform(sf::st_crs(e))
  F_pt <- sf::st_coordinates(from_pt)[1, 1:2]
  if (sum((B - F_pt)^2) < sum((A - F_pt)^2)) sf::st_geometry(e) <- sf::st_sfc(lwgeom::st_reverse(g), crs=sf::st_crs(e))
  e
}

route_line_between_vertices <- function(v_from, v_to) {
  v_from <- as.character(v_from); v_to <- as.character(v_to)
  p <- try(dodgr::dodgr_paths(graph_w, from=v_from, to=v_to), silent=TRUE)
  if (inherits(p, "try-error") || is.null(p) || length(p[[1]]) == 0) return(NULL)
  v_seq <- as.character(p[[1]][[1]])
  if (length(v_seq) < 2) return(NULL)
  vtbl_from <- unique(data.frame(id=as.character(graph_w$from_id), lon=graph_w$from_lon, lat=graph_w$from_lat))
  vtbl_to <- unique(data.frame(id=as.character(graph_w$to_id), lon=graph_w$to_lon, lat=graph_w$to_lat))
  vtbl <- unique(rbind(vtbl_from, vtbl_to))
  coords <- vtbl[match(v_seq, vtbl$id), c("lon","lat")]
  if (anyNA(coords)) return(NULL)
  sf::st_sfc(sf::st_linestring(as.matrix(coords)), crs=4326) |> sf::st_transform(target_crs) %>% st_sf(geometry=.)
}

project_point_to_edge <- function(pt, edge) {
  np <- st_nearest_points(st_geometry(pt), st_geometry(edge))
  xy <- st_coordinates(np[[1]])
  st_as_sf(data.frame(geometry=st_sfc(st_point(xy[2,1:2]), crs=st_crs(pt))))
}

edge_fraction <- function(edge, proj) {
  xy <- st_coordinates(edge)[,1:2]; A <- xy[1,]; B <- xy[nrow(xy),]; P <- st_coordinates(proj)[1,]
  t <- sum((P-A)*(B-A)) / sum((B-A)^2); max(0, min(1, t))
}

edge_segment_geom <- function(edge, a, b) {
  st_as_sf(data.frame(geometry=st_sfc(lwgeom::st_linesubstring(st_geometry(edge)[[1]], min(a,b), max(a,b)), crs=st_crs(edge))))
}

trim_route_to_point <- function(route_sf_m, pb_sf_m, snap_tol_m = 5) {
  if (is.null(route_sf_m)) return(list(route_trim=NULL, trim_len_m=NA_real_))
  crs_use <- sf::st_crs(route_sf_m); rgeom <- sf::st_geometry(route_sf_m)
  rline <- suppressWarnings(sf::st_cast(rgeom, "LINESTRING"))
  if (length(rline) == 0) return(list(route_trim=sf::st_as_sf(route_sf_m), trim_len_m=NA))
  r_ls <- rline[1]
  np <- sf::st_nearest_points(sf::st_geometry(pb_sf_m), r_ls)
  on_pt <- sf::st_sfc(sf::st_point(sf::st_coordinates(np[[1]])[2, 1:2]), crs=crs_use)
  sp <- try(lwgeom::st_split(r_ls, on_pt), silent=TRUE)
  parts <- suppressWarnings(sf::st_collection_extract(sp, "LINESTRING"))
  if (length(parts) < 2) {
    blade <- sf::st_buffer(on_pt, dist=0.001)
    sp_blade <- try(lwgeom::st_split(r_ls, blade), silent=TRUE)
    parts <- suppressWarnings(sf::st_collection_extract(sp_blade, "LINESTRING"))
  }
  if (length(parts) >= 2) {
    start_pt <- sf::st_sfc(sf::st_point(sf::st_coordinates(r_ls)[1, 1:2]), crs=crs_use)
    starts <- lapply(parts, function(ls) sf::st_sfc(sf::st_point(sf::st_coordinates(ls)[1, 1:2]), crs=crs_use))
    d <- vapply(starts, function(s) as.numeric(sf::st_distance(s, start_pt))[1], numeric(1))
    candidate <- parts[[which.min(d)]]; route_trim <- sf::st_sf(geometry=sf::st_sfc(candidate, crs=crs_use))
    return(list(route_trim=route_trim, trim_len_m=as.numeric(sf::st_length(route_trim))))
  }
  out <- sf::st_sf(geometry=sf::st_sfc(r_ls, crs=crs_use)); list(route_trim=out, trim_len_m=as.numeric(sf::st_length(out)))
}

# ------------------------------------------------------------------------------
# 5. CALCULATION LOGIC
# ------------------------------------------------------------------------------
edge_shortest_route_between_projections_dir <- function(from_pt_m, to_pt_m, tol_on_route_m = 5) {
  ea <- roads_sf[sf::st_nearest_feature(from_pt_m, roads_sf), ]
  eb <- roads_sf[sf::st_nearest_feature(to_pt_m,    roads_sf), ]
  ea <- orient_edge_geom_to_from(ea); eb <- orient_edge_geom_to_from(eb)
  pa <- project_point_to_edge(from_pt_m, ea); pb <- project_point_to_edge(to_pt_m, eb)
  fa <- edge_fraction(ea, pa); fb <- edge_fraction(eb, pb)
  a_to <- as.character(ea$to_id[1]); b_from <- as.character(eb$from_id[1])
  
  a_edge_part_m <- as.numeric(ea$edge_len_m[1]) * (1 - fa)
  seg_from <- edge_segment_geom(ea, fa, 1)
  b_edge_part_m <- as.numeric(eb$edge_len_m[1]) * fb
  seg_to <- edge_segment_geom(eb, 0, fb)
  
  dm <- dodgr::dodgr_dists(graph_w, from = a_to, to = b_from)[1, 1]
  net_m <- as.numeric(dm)
  net_route <- NULL
  
  if (is.finite(net_m)) {
    net_route <- route_line_between_vertices(a_to, b_from)
    if (!is.null(net_route)) {
      d_pb <- as.numeric(sf::st_distance(sf::st_geometry(pb), sf::st_geometry(net_route)))
      if (is.finite(d_pb) && d_pb <= max(2, tol_on_route_m)) {
        tr <- trim_route_to_point(net_route, pb, snap_tol_m = 5)
        if (!is.na(tr$trim_len_m)) { net_route <- tr$route_trim; net_m <- tr$trim_len_m; b_edge_part_m <- 0; seg_to <- NULL }
      }
    }
  } else {
    return(list(dist_total_m=NA)) 
  }
  
  best_total <- a_edge_part_m + net_m + b_edge_part_m
  list(proj_from=pa, proj_to=pb, seg_from=seg_from, seg_to=seg_to, net_route=net_route, dist_total_m=best_total, dist_net_m=net_m)
}







