  mapview(new_line, color = "green", lwd = 4, layer.name = "Fixed_V1_to_V4") +
  
  mapview(st_as_sf(data.frame(x=new_coords[,1], y=new_coords[,2]), 
                   coords=c("x","y"), crs=st_crs(original_line)), 
          color = "green", cex = 3, layer.name = "Kept_Vertices")


