diagnostic_maps <- list()

message("🔄 Generating diagnostic maps...")

for(seg_id in problem_ids) {
  
  # --- A. Get Data ---
  if(seg_id > length(segment_results) || is.null(segment_results[[seg_id]])) {
    message(paste("⚠️ Segment", seg_id, "not found or failed. Skipping."))
    next
  }
  
  dat <- segment_results[[seg_id]]$res
  
  # --- B. Combine Path Parts ---
  parts <- list()
  if(!is.null(dat$seg_from))  parts[[1]] <- dat$seg_from
  if(!is.null(dat$net_route)) parts[[length(parts)+1]] <- dat$net_route
  if(!is.null(dat$seg_to))    parts[[length(parts)+1]] <- dat$seg_to
  
  if(length(parts) == 0) {
    message(paste("⚠️ Segment", seg_id, "has no geometry. Skipping."))
    next
  }
  
  full_line <- do.call(rbind, parts)
  
  # --- C. Extract Vertices & ID ---
  coords <- st_coordinates(full_line)
  df_points <- data.frame(
    ID = 1:nrow(coords),
    X = coords[,1],
    Y = coords[,2]
  )
  points_sf <- st_as_sf(df_points, coords = c("X", "Y"), crs = st_crs(full_line))
  
  # --- D. Generate Map ---
  m <- mapview(full_line, color = "blue", lwd = 4, alpha = 0.5, 
               layer.name = paste("Path Seg", seg_id)) +
    mapview(points_sf, 
            zcol = "ID", 
            col.regions = topo.colors(nrow(points_sf)), 
            cex = 6, 
            label = points_sf$ID, 
            layer.name = paste("Vertices Seg", seg_id))
  
  # Save to list
  diagnostic_maps[[as.character(seg_id)]] <- m
}

