# ==============================================================================
# BATCH MANUAL FIX PREVIEW: SEGMENTS 3 & 6
# Goal: Connect V1 -> V4 directly (Skip V2, V3) for both segments
# ==============================================================================
library(sf)
library(mapview)
library(dplyr)

targets <- c(3, 6)
preview_maps <- list()

for(seg_id in targets) {
  
  # 1. EXTRACT ORIGINAL DATA
  dat <- segment_results[[seg_id]]$res
  
  # Reconstruct original line
  parts <- list()
  if(!is.null(dat$seg_from))  parts[[1]] <- dat$seg_from
  if(!is.null(dat$net_route)) parts[[length(parts)+1]] <- dat$net_route
  if(!is.null(dat$seg_to))    parts[[length(parts)+1]] <- dat$seg_to
  original_line <- do.call(rbind, parts)
  
  # 2. APPLY THE FIX
  coords <- st_coordinates(original_line)
  
  # Logic: Keep V1, Skip V2/V3, Keep V4 -> End
  # (Safety check: ensure segment actually has enough vertices)
  if(nrow(coords) >= 4) {
    keep_indices <- c(1, 4:nrow(coords))
    new_coords <- coords[keep_indices, 1:2]
    
    # Create New Geometry
    new_line <- st_linestring(new_coords) %>% 
      st_sfc(crs = st_crs(original_line)) %>% 
      st_sf(geometry = .)
    
    # 3. CALCULATE DISTANCE CHANGE
    old_dist <- as.numeric(st_length(original_line))
    new_dist <- as.numeric(st_length(new_line))
    diff_m   <- round(old_dist - new_dist, 2)
    
    message(paste0("📍 Segment ", seg_id, ": Removed ", diff_m, " meters (Loop length)"))
    
    # 4. GENERATE MAP
    m <- mapview(original_line, color = "red", lwd = 6, alpha = 0.4, 
                 layer.name = paste("Original Seg", seg_id)) +
      mapview(new_line, color = "green", lwd = 4, 
              layer.name = paste("Fixed Seg", seg_id)) +
      mapview(st_as_sf(data.frame(x=new_coords[,1], y=new_coords[,2]), 
                       coords=c("x","y"), crs=st_crs(original_line)), 
              color = "green", cex = 3, layer.name = "Kept Vertices")
    
    preview_maps[[as.character(seg_id)]] <- m
    
  } else {
    message(paste("⚠️ Segment", seg_id, "has fewer than 4 vertices! Cannot skip V2/V3."))
  }
}

message("✅ Previews generated. Run the lines below to inspect:")

preview_maps[["3"]]  # Check Segment 3
preview_maps[["6"]]  # Check Segment 6

# ==============================================================================
# COMMIT BATCH FIX: SEGMENTS 3 & 6
# Action: Force connection V1 -> V4 (Skipping V2, V3)
# ==============================================================================
library(sf)
library(dplyr)

targets <- c(3, 6)

for(target_seg in targets) {
  
  # 1. Get Original Data
  dat <- segment_results[[target_seg]]$res
  
  # Reconstruct full line to ensure we have all coordinates
  parts <- list()
  if(!is.null(dat$seg_from))  parts[[1]] <- dat$seg_from
  if(!is.null(dat$net_route)) parts[[length(parts)+1]] <- dat$net_route
  if(!is.null(dat$seg_to))    parts[[length(parts)+1]] <- dat$seg_to
  
  original_line <- do.call(rbind, parts)
  coords <- st_coordinates(original_line)
  
  # 2. APPLY THE FIX
  # Keep Vertex 1, skip 2 & 3, keep 4 to End
  if(nrow(coords) >= 4) {
    keep_indices <- c(1, 4:nrow(coords)) 
    new_coords <- coords[keep_indices, 1:2] 
    
    # 3. Create New Geometry
    clean_sf <- st_linestring(new_coords) %>% 
      st_sfc(crs = st_crs(original_line)) %>% 
      st_sf(geometry = .)
    
    # 4. Overwrite the Result in the List
    segment_results[[target_seg]]$res$net_route <- clean_sf
    segment_results[[target_seg]]$res$seg_from  <- NULL
    segment_results[[target_seg]]$res$seg_to    <- NULL
    
    # 5. Update Distance
    new_dist <- as.numeric(st_length(clean_sf))
    segment_results[[target_seg]]$res$dist_total_m <- new_dist
    
    message(paste0("✅ Fix Committed for Segment ", target_seg))
    message(paste0("   New Distance: ", round(new_dist, 2), " meters"))
    
  } else {
    message(paste0("⚠️ Segment ", target_seg, " skipped (Not enough vertices to skip 2 & 3)."))
  }
}

