for(comb in list(list(a_to_3, b_from_3), list(a_to_3, b_to_3), list(a_from_3, b_from_3), list(a_from_3, b_to_3))) {
  dm <- try(dodgr::dodgr_dists(graph_w, from = comb[[1]], to = comb[[2]])[1, 1], silent = TRUE)
  if(!inherits(dm, "try-error") && is.finite(dm) && dm < best_dm_3) {
    test_route <- route_line_between_vertices(comb[[1]], comb[[2]])
    if(!is.null(test_route)) { best_dm_3 <- dm; best_3 <- test_route }
  }
}
