end_pt      <- st_coordinates(segment_results[[28]]$res$proj_to)
full_coords <- st_coordinates(path_28_raw)

# 2. Build the full bridged LINESTRING
# Skip V1, use V2 through second-to-last, and cap with Snap End
new_coords_28 <- rbind(
  matrix(start_pt[1, 1:2], ncol = 2),                   # Start Snap
  matrix(full_coords[2:(nrow(full_coords)-1), 1:2], ncol = 2), # V2 to second-to-last
  matrix(end_pt[1, 1:2], ncol = 2)                       # End Snap
)

# 3. Update the segment_results list with clean SF structure
