library(sf)
library(mapview)

# Function to create the optimized path (Start Snap -> V2 to Penultimate -> End Snap)
preview_bridge <- function(seg_id) {
  path_raw <- segment_results[[seg_id]]$res$net_route
  crs_native <- st_crs(path_raw)
  
  start_pt <- st_coordinates(segment_results[[seg_id]]$res$proj_from)
  end_pt   <- st_coordinates(segment_results[[seg_id]]$res$proj_to)
  full_coords <- st_coordinates(path_raw)
  
  # Construct geometry: Skip V1, jump to V2, end at Snap point
  new_coords <- rbind(
    matrix(start_pt[1, 1:2], ncol = 2),
    matrix(full_coords[2:(nrow(full_coords)-1), 1:2], ncol = 2),
    matrix(end_pt[1, 1:2], ncol = 2)
  )
  
  return(st_sf(geometry = st_sfc(st_linestring(new_coords), crs = crs_native)))
}

# Generate proposed paths
