  mapview(proposed_17, color = "cyan", lwd = 6, layer.name = "Proposed 17") +
  mapview(segment_results[[20]]$res$net_route, color = "red", lwd = 1, layer.name = "Old 20") +
  mapview(proposed_20, color = "gold", lwd = 6, layer.name = "Proposed 20") +
  mapview(segment_results[[17]]$res$proj_from, col.regions = "cyan") +
  mapview(segment_results[[20]]$res$proj_from, col.regions = "cyan")

