# --- 2. CONSTRUCT GEOMETRY ---
# Sequence: 
# 1. Snap Start (Cyan)
# 2. ALL Original Vertices from V2 through the very last original vertex
# 3. Snap End (Magenta)
new_coords_20 <- rbind(
  matrix(start_pt[1, 1:2], ncol = 2),              # Start Snap
  matrix(full_coords[2:nrow(full_coords), 1:2], ncol = 2), # V2 through ALL remaining
  matrix(end_pt[1, 1:2], ncol = 2)                 # End Snap
)

proposed_geom_20 <- st_linestring(new_coords_20)
proposed_sf_20   <- st_sf(geometry = st_sfc(proposed_geom_20, crs = crs_native))

# --- 3. VISUALIZE COMPARISON ---
mapview(path_20_raw, color = "red", lwd = 2, layer.name = "Original Hook") +
  mapview(proposed_sf_20, color = "gold", lwd = 6, layer.name = "Corrected Segment 20") +
  mapview(segment_results[[20]]$res$proj_from, col.regions = "cyan", cex = 6) +
  mapview(segment_results[[20]]$res$proj_to, col.regions = "magenta", cex = 6)

