geom_list <- list()
if(exists("segment_results")) {
  for(i in 1:length(segment_results)) {
    res <- segment_results[[i]]$res
    if(!is.null(res$seg_from))  geom_list[[length(geom_list) + 1]] <- st_geometry(res$seg_from)
    if(!is.null(res$net_route)) geom_list[[length(geom_list) + 1]] <- st_geometry(res$net_route)
    if(!is.null(res$seg_to))    geom_list[[length(geom_list) + 1]] <- st_geometry(res$seg_to)
  }
} else {
  stop("❌ 'segment_results' not found.")
}

# 2. MERGE INTO ONE LINE
combined_sfc <- do.call(c, geom_list)
full_route_union <- st_union(combined_sfc)
full_route_sf <- st_sf(geometry = full_route_union)
st_crs(full_route_sf) <- st_crs(geom_list[[1]]) 

# 3. USE MANUAL ROUTE NUMBER (SMART CLEANING)
# First, replace " | " with "_" so "181 | 2" becomes "7_1"
clean_route_num <- gsub(" \\| ", "_", MANUAL_ROUTE_NUM)
