# ==============================================================================
# MASTER SCRIPT: ROUTE 182 | 1 (CALCULATE + FIX + MAP)
# ==============================================================================

# 1. SETUP & SELECTION
rm(route_data) # <--- ADD THIS LINE! Deletes the old Route data
target_route_id <- "182 | 1"
code_seq <- master_route_codes[[target_route_id]]

# Build Route Data
stops_db <- bus_proj %>%
  filter(busstopcode %in% code_seq) %>%
  distinct(busstopcode, .keep_all=TRUE)

seq_table <- tibble(ordering=1:length(code_seq), busstopcode=code_seq)
route_data <- seq_table %>%
  left_join(stops_db, by="busstopcode") %>%
  arrange(ordering) %>%
  st_as_sf()

message(paste0("🚀 Processing Route ", target_route_id, ": ", nrow(route_data), " Stops..."))

# 2. INITIALIZE STORAGE (CRITICAL STEP)
segment_results <- list() 
results_df <- data.frame()
total_segments <- nrow(route_data) - 1

# 3. MAIN CALCULATION LOOP
message("🔄 Running initial path calculations...")
pb <- txtProgressBar(min = 0, max = total_segments, style = 3)

for(i in 1:total_segments) {
  start_pt <- route_data[i, ]
  end_pt   <- route_data[i+1, ]
  start_m  <- st_transform(start_pt, target_crs)
  end_m    <- st_transform(end_pt, target_crs)
  
  # Calculate Route
  res <- edge_shortest_route_between_projections_dir(start_m, end_m)
  
  # SAVE RAW DATA into the list so we can modify it later
  segment_results[[i]] <- list(
    res = res,
    start_m = start_m,
    end_m = end_m
  )
  
  setTxtProgressBar(pb, i)
}
close(pb)

# ==============================================================================
# Preview SEGMENT 7 (V2 BRIDGE + ALL ROAD VERTICES)
# ==============================================================================

library(sf)
library(mapview)

# --- 1. EXTRACT DATA ---
path_7_raw  <- segment_results[[7]]$res$net_route
crs_native  <- st_crs(path_7_raw)

# Get Snap points (Cyan and Magenta)
start_pt    <- st_coordinates(segment_results[[7]]$res$proj_from)
end_pt      <- st_coordinates(segment_results[[7]]$res$proj_to)
full_coords <- st_coordinates(path_7_raw)

# --- 2. CONSTRUCT GEOMETRY ---
# Sequence: 
# 1. Snap Start (Cyan)
# 2. ALL Original Vertices from V2 through the very last original vertex
# 3. Snap End (Magenta)
new_coords_7 <- rbind(
  matrix(start_pt[1, 1:2], ncol = 2),              # Start Snap
  matrix(full_coords[2:nrow(full_coords), 1:2], ncol = 2), # V2 through ALL remaining
  matrix(end_pt[1, 1:2], ncol = 2)                 # End Snap
)

proposed_geom_7 <- st_linestring(new_coords_7)
proposed_sf_7   <- st_sf(geometry = st_sfc(proposed_geom_7, crs = crs_native))

# --- 3. VISUALIZE COMPARISON ---
mapview(path_7_raw, color = "red", lwd = 2, layer.name = "Original Path") +
  mapview(proposed_sf_7, color = "purple", lwd = 6, layer.name = "Corrected Segment 7") +
  mapview(segment_results[[7]]$res$proj_from, col.regions = "cyan", cex = 6) +
  mapview(segment_results[[7]]$res$proj_to, col.regions = "magenta", cex = 6)

# ==============================================================================
# PERMANENT COMMIT: SEGMENT 7 (V2 BRIDGE + ALL ROAD VERTICES)
# ==============================================================================

# 1. Access native CRS and coordinates
path_7_raw <- segment_results[[7]]$res$net_route
crs_native  <- st_crs(path_7_raw)

# Extract Snap points and existing vertex coordinates
start_pt    <- st_coordinates(segment_results[[7]]$res$proj_from)
end_pt      <- st_coordinates(segment_results[[7]]$res$proj_to)
full_coords <- st_coordinates(path_7_raw)

# 2. Build the optimized LINESTRING
# Sequence: Start Snap -> V2 through the VERY LAST vertex -> End Snap
new_coords_7 <- rbind(
  matrix(start_pt[1, 1:2], ncol = 2),                   # 1. Start Snap
  matrix(full_coords[2:nrow(full_coords), 1:2], ncol = 2), # 2. V2 to the end of road
  matrix(end_pt[1, 1:2], ncol = 2)                       # 3. End Snap
)

# 3. Update the segment_results list with clean SF structure
segment_results[[7]]$res$net_route <- st_sf(
  geometry = st_sfc(st_linestring(new_coords_7), crs = crs_native)
)

# 4. Update the total distance field
segment_results[[7]]$res$dist_total_m <- as.numeric(st_length(segment_results[[7]]$res$net_route))

# 5. Clean up any leftover detour metadata
segment_results[[7]]$res$seg_from <- NULL
segment_results[[7]]$res$seg_to   <- NULL

message(paste0("✅ Success: Segment 7 finalized. New distance: ", 
               round(segment_results[[7]]$res$dist_total_m, 2), " meters."))

# ==============================================================================
# 2. GENERATE FINAL MAPS & STATS
# ==============================================================================
map_list <- list()
final_stats <- data.frame()

message("🎨 Generating maps...")
pb_maps <- txtProgressBar(min = 0, max = total_segments, style = 3)

for(i in 1:total_segments) {
  
  dat <- segment_results[[i]]
  res <- dat$res
  stop_a <- dat$start_m
  stop_b <- dat$end_m
  
  if(!is.na(res$dist_total_m)) {
    dist_val <- round(res$dist_total_m, 2)
    
    # Combine components (Network + any remaining Stubs)
    comp <- list()
    if(!is.null(res$seg_from)) comp[[1]] <- res$seg_from
    if(!is.null(res$net_route)) comp[[length(comp)+1]] <- res$net_route
    if(!is.null(res$seg_to)) comp[[length(comp)+1]] <- res$seg_to
    
    road_path <- if(length(comp) > 0) do.call(rbind, comp) else NULL
    
    # Save Stats
    final_stats <- rbind(final_stats, data.frame(
      Segment_ID = i,
      From = route_data$busstopname[i],
      To = route_data$busstopname[i+1],
      Distance_m = dist_val,
      Status = "✅ OK"
    ))
    
    # Save Map
    if(!is.null(road_path)) {
      m_single <- mapview(road_path, color = "blue", lwd = 5, 
                          layer.name = paste("Segment", i), label = paste(dist_val, "m")) +
        mapview(res$proj_from, col.regions = "cyan", cex = 6, layer.name = "Snap Start") +
        mapview(res$proj_to, col.regions = "magenta", cex = 6, layer.name = "Snap End") +
        mapview(rbind(stop_a, stop_b), col.regions = "red", cex = 3, layer.name = "Original GPS")
      
      map_list[[i]] <- m_single
    }
  } else {
    # Failed Segment
    final_stats <- rbind(final_stats, data.frame(
      Segment_ID = i, From = route_data$busstopname[i], To = route_data$busstopname[i+1],
      Distance_m = NA, Status = "❌ FAIL"
    ))
    map_list[[i]] <- NULL
  }
  setTxtProgressBar(pb_maps, i)
}
close(pb_maps)

print(final_stats)
message("✅ Done. Check map_list[[6]], map_list[[31]], map_list[[34]] to verify fixes.")

# Show the first map immediately
map_list[[7]]


# Initialize the counter (Run this once)
current_seg <- 1

# FUNCTION: Run this block repeatedly to see the next segment
print(map_list[[current_seg]])
current_seg <- current_seg + 1
print(map_list[[current_seg]])

