# 1. SETUP & SELECTION
rm(route_data) # <--- ADD THIS LINE! Deletes the old Route data
target_route_id <- "231 | 2"
code_seq <- master_route_codes[[target_route_id]]

# Build Route Data
stops_db <- bus_proj %>%
  filter(busstopcode %in% code_seq) %>%
  distinct(busstopcode, .keep_all=TRUE)

seq_table <- tibble(ordering=1:length(code_seq), busstopcode=code_seq)
route_data <- seq_table %>%
  left_join(stops_db, by="busstopcode") %>%
  arrange(ordering) %>%
  st_as_sf()

message(paste0("🚀 Processing Route ", target_route_id, ": ", nrow(route_data), " Stops..."))

# 2. INITIALIZE STORAGE (CRITICAL STEP)
segment_results <- list() 
results_df <- data.frame()
total_segments <- nrow(route_data) - 1

# 3. MAIN CALCULATION LOOP
message("🔄 Running initial path calculations...")
pb <- txtProgressBar(min = 0, max = total_segments, style = 3)

for(i in 1:total_segments) {
  start_pt <- route_data[i, ]
  end_pt   <- route_data[i+1, ]
  start_m  <- st_transform(start_pt, target_crs)
  end_m    <- st_transform(end_pt, target_crs)
  
  # Calculate Route
  res <- edge_shortest_route_between_projections_dir(start_m, end_m)
  
  # SAVE RAW DATA into the list so we can modify it later
  segment_results[[i]] <- list(
    res = res,
    start_m = start_m,
    end_m = end_m
  )
  
  setTxtProgressBar(pb, i)
}
close(pb)


# ==============================================================================
# FIX SEGMENT 2 - PREVIEW
# ==============================================================================

i <- 2
dat <- segment_results[[i]]

# Get original snap points (KEEP THESE)
orig_proj_from <- dat$res$proj_from
orig_proj_to <- dat$res$proj_to

# Get the original edges
ea <- roads_sf[sf::st_nearest_feature(dat$start_m, roads_sf), ]
eb <- roads_sf[sf::st_nearest_feature(dat$end_m, roads_sf), ]
ea <- orient_edge_geom_to_from(ea)
eb <- orient_edge_geom_to_from(eb)

# Original fractions
fa <- edge_fraction(ea, orig_proj_from)
fb <- edge_fraction(eb, orig_proj_to)

# Vertex IDs
a_from <- as.character(ea$from_id[1])
a_to <- as.character(ea$to_id[1])
b_from <- as.character(eb$from_id[1])
b_to <- as.character(eb$to_id[1])

message(paste("Edge A:", a_from, "->", a_to))
message(paste("Edge B:", b_from, "->", b_to))

# Test all 4 vertex combinations
combinations <- list(
  list(from_v = a_to, to_v = b_from, seg_from_range = c(fa, 1), seg_to_range = c(0, fb)),
  list(from_v = a_to, to_v = b_to, seg_from_range = c(fa, 1), seg_to_range = c(fb, 1)),
  list(from_v = a_from, to_v = b_from, seg_from_range = c(0, fa), seg_to_range = c(0, fb)),
  list(from_v = a_from, to_v = b_to, seg_from_range = c(0, fa), seg_to_range = c(fb, 1))
)

best_option <- NULL
best_total <- Inf

for(k in 1:length(combinations)) {
  comb <- combinations[[k]]
  dm <- try(dodgr::dodgr_dists(graph_w, from = comb$from_v, to = comb$to_v)[1, 1], silent = TRUE)
  
  if(!inherits(dm, "try-error") && is.finite(dm)) {
    seg_from_len <- as.numeric(ea$edge_len_m[1]) * abs(comb$seg_from_range[2] - comb$seg_from_range[1])
    seg_to_len <- as.numeric(eb$edge_len_m[1]) * abs(comb$seg_to_range[2] - comb$seg_to_range[1])
    total <- seg_from_len + dm + seg_to_len
    
    message(paste("Option", k, ":", comb$from_v, "->", comb$to_v, "| Total:", round(total, 1), "m"))
    
    test_route <- route_line_between_vertices(comb$from_v, comb$to_v)
    if(!is.null(test_route) && total < best_total) {
      best_total <- total
      best_option <- list(k = k, from_v = comb$from_v, to_v = comb$to_v,
                          seg_from_range = comb$seg_from_range, seg_to_range = comb$seg_to_range,
                          dm = dm, route = test_route)
    }
  } else {
    message(paste("Option", k, ":", comb$from_v, "->", comb$to_v, "| ❌ No path"))
  }
}

if(!is.null(best_option)) {
  message(paste("\n✅ Best option:", best_option$k, "| Total:", round(best_total, 1), "m"))
  
  # Build preview
  net_route_preview <- best_option$route
  
  # Old route for comparison
  comp_old <- list()
  if(!is.null(dat$res$seg_from)) comp_old[[1]] <- dat$res$seg_from
  if(!is.null(dat$res$net_route)) comp_old[[length(comp_old)+1]] <- dat$res$net_route
  if(!is.null(dat$res$seg_to)) comp_old[[length(comp_old)+1]] <- dat$res$seg_to
  old_path <- if(length(comp_old) > 0) do.call(rbind, comp_old) else NULL
  
  # Preview map
  preview_map_2 <- mapview(old_path, color = "red", lwd = 4, layer.name = "OLD Route (red)") +
    mapview(net_route_preview, color = "green", lwd = 4, layer.name = "NEW Route (green)") +
    mapview(orig_proj_from, col.regions = "cyan", cex = 8, layer.name = "Snap Start") +
    mapview(orig_proj_to, col.regions = "magenta", cex = 8, layer.name = "Snap End")
  
  message("\n👀 Run: preview_map_2")
} else {
  message("❌ No connected path found")
}

# ==============================================================================
# COMMIT SEGMENT 2
# ==============================================================================

crs_native <- st_crs(net_route_preview)
start_pt <- st_coordinates(orig_proj_from)
end_pt <- st_coordinates(orig_proj_to)
net_coords <- st_coordinates(net_route_preview)

new_coords_2 <- rbind(
  matrix(start_pt[1, 1:2], ncol = 2),
  matrix(net_coords[, 1:2], ncol = 2),
  matrix(end_pt[1, 1:2], ncol = 2)
)

segment_results[[2]]$res$net_route <- st_sf(geometry = st_sfc(st_linestring(new_coords_2), crs = crs_native))
segment_results[[2]]$res$dist_total_m <- as.numeric(st_length(segment_results[[2]]$res$net_route))
segment_results[[2]]$res$seg_from <- NULL
segment_results[[2]]$res$seg_to <- NULL

message(paste0("✅ Segment 2 finalized. Distance: ", round(segment_results[[2]]$res$dist_total_m, 2), " m"))

