library(sf)
library(mapview)

# Function to generate the optimized path logic
optimize_bridge <- function(seg_id) {
  res         <- segment_results[[seg_id]]$res
  path_raw    <- res$net_route
  crs_native  <- st_crs(path_raw)
  
  start_pt    <- st_coordinates(res$proj_from)
  end_pt      <- st_coordinates(res$proj_to)
  full_coords <- st_coordinates(path_raw)
  
  # Logic: Start Snap -> V2 to End of Road -> End Snap
  new_coords <- rbind(
    matrix(start_pt[1, 1:2], ncol = 2),
    matrix(full_coords[2:nrow(full_coords), 1:2], ncol = 2),
    matrix(end_pt[1, 1:2], ncol = 2)
  )
  
  st_sf(geometry = st_sfc(st_linestring(new_coords), crs = crs_native), 
        segment = paste("Segment", seg_id))
}

# --- 1. GENERATE PREVIEWS ---
preview_25 <- optimize_bridge(25)
preview_30 <- optimize_bridge(30)

# --- 2. VISUALIZE BOTH ---
mapview(preview_25, color = "cyan", lwd = 4, layer.name = "Preview Seg 25") +
  mapview(preview_30, color = "yellow", lwd = 4, layer.name = "Preview Seg 30") +
  mapview(segment_results[[25]]$res$proj_from, col.regions = "blue", layer.name = "Start 25") +
  mapview(segment_results[[30]]$res$proj_from, col.regions = "orange", layer.name = "Start 30")


# ==============================================================================
# PERMANENT COMMIT: SEGMENTS 25 & 30 (START SNAP -> V2 BRIDGE -> END SNAP)
# ==============================================================================

# List of segments to process with the V2 Bridge logic
target_segments <- c(25, 30)

for (seg_id in target_segments) {
  
  # 1. Access native CRS and coordinates
  res         <- segment_results[[seg_id]]$res
  path_raw    <- res$net_route
  crs_native  <- st_crs(path_raw)
  
  start_pt    <- st_coordinates(res$proj_from)
  end_pt      <- st_coordinates(res$proj_to)
  full_coords <- st_coordinates(path_raw)
  
  # 2. Build the optimized LINESTRING
  # Sequence: Start Snap -> V2 through the VERY LAST vertex -> End Snap
  new_coords <- rbind(
    matrix(start_pt[1, 1:2], ncol = 2),                   # 1. Start Snap
    matrix(full_coords[2:nrow(full_coords), 1:2], ncol = 2), # 2. V2 to end of road
    matrix(end_pt[1, 1:2], ncol = 2)                       # 3. End Snap
  )
  
  # 3. Update the segment_results list with clean SF structure
  segment_results[[seg_id]]$res$net_route <- st_sf(
    geometry = st_sfc(st_linestring(new_coords), crs = crs_native)
  )
  
  # 4. Update the total distance field
  segment_results[[seg_id]]$res$dist_total_m <- as.numeric(st_length(segment_results[[seg_id]]$res$net_route))
  
  # 5. Clean up leftover metadata
  segment_results[[seg_id]]$res$seg_from <- NULL
  segment_results[[seg_id]]$res$seg_to   <- NULL
  
  message(paste0("✅ Success: Segment ", seg_id, " finalized. New distance: ", 
                 round(segment_results[[seg_id]]$res$dist_total_m, 2), " meters."))
}

