for(i in 1:total_segments) {
  start_pt <- route_data[i, ]
  end_pt   <- route_data[i+1, ]
  start_m  <- st_transform(start_pt, target_crs)
  end_m    <- st_transform(end_pt, target_crs)
  
  # Calculate Route
  res <- edge_shortest_route_between_projections_dir(start_m, end_m)
  
  # SAVE RAW DATA into the list so we can modify it later
  segment_results[[i]] <- list(
    res = res,
    start_m = start_m,
    end_m = end_m
  )
  
  setTxtProgressBar(pb, i)
}
close(pb)

# ==============================================================================
# Preview SEGMENT 16 (START SNAP -> V2 -> V3... -> END SNAP)
# ==============================================================================

library(sf)
library(mapview)

# 1. FORCE COORDINATE SYSTEM (EPSG:4326)
target_crs <- 4326

# Re-project to ensure we are using degrees (Riyadh ~24, 46)
path_16_raw <- st_transform(segment_results[[16]]$res$net_route, target_crs)
snap_start  <- st_transform(segment_results[[16]]$res$proj_from, target_crs)
snap_end    <- st_transform(segment_results[[16]]$res$proj_to, target_crs)

# 2. EXTRACT COORDINATES
s_coords <- st_coordinates(snap_start)[1, 1:2]
e_coords <- st_coordinates(snap_end)[1, 1:2]
# Extract all road vertices from the original network (V1 to V14)
road_v   <- st_coordinates(path_16_raw)[, 1:2]

# 3. CONSTRUCT THE STITCHED GEOMETRY
# Sequence: Start Snap -> V2 -> V3 ... until end of road vertices -> End Snap
# We use road_v[2:nrow(road_v), ] to explicitly skip V1
preview_matrix_16 <- rbind(
  s_coords,                  # 1. Start Snap Point
  road_v[2:nrow(road_v), ],   # 2. Road Vertices V2 through V14
  e_coords                   # 3. End Snap Point
)

# Create the SF object for the preview
preview_sf_16 <- st_sf(
  geometry = st_sfc(st_linestring(preview_matrix_16), crs = target_crs)
)

# 4. LOCAL VISUALIZATION
mapview(preview_sf_16, color = "blue", lwd = 4, layer.name = "Preview Fixed Seg 16") +
  mapview(snap_start, col.regions = "cyan", layer.name = "Start Stop") +
  mapview(snap_end, col.regions = "magenta", layer.name = "End Stop")

# ==============================================================================
# PERMANENT COMMIT: SEGMENT 16 (STRICT CRS ALIGNMENT WITH SEGMENT 7)
# ==============================================================================

# 1. Use Segment 7 as the "Master CRS" reference
master_crs <- st_crs(segment_results[[7]]$res$net_route)

# 2. Transform ALL Segment 16 components to the Master CRS first
s16_net_ref   <- st_transform(segment_results[[16]]$res$net_route, master_crs)
s16_start_ref <- st_transform(segment_results[[16]]$res$proj_from, master_crs)
s16_end_ref   <- st_transform(segment_results[[16]]$res$proj_to, master_crs)

# 3. Now extract coordinates that are guaranteed to be in the same units
start_coords <- st_coordinates(s16_start_ref)[1, 1:2]
end_coords   <- st_coordinates(s16_end_ref)[1, 1:2]
road_coords  <- st_coordinates(s16_net_ref)[, 1:2]

# 4. Build the matrix skipping V1
# Start Snap -> V2 to End of Road -> End Snap
final_matrix_16 <- rbind(
  start_coords,
  road_coords[2:nrow(road_coords), ],
  end_coords
)

# 5. COMMIT: Save with the Master CRS
segment_results[[16]]$res$net_route <- st_sf(
  geometry = st_sfc(st_linestring(final_matrix_16), crs = master_crs)
)

# 6. Update Distance and Clean
segment_results[[16]]$res$dist_total_m <- as.numeric(st_length(segment_results[[16]]$res$net_route))
segment_results[[16]]$res$seg_from <- NULL
segment_results[[16]]$res$seg_to   <- NULL

message(paste0("✅ Fixed: Segment 16 now matches Segment 7 CRS. Distance: ", 
               round(segment_results[[16]]$res$dist_total_m, 2), " meters."))

# ==============================================================================
# 2. GENERATE FINAL MAPS & STATS
# ==============================================================================
map_list <- list()
final_stats <- data.frame()

message("🎨 Generating maps...")
pb_maps <- txtProgressBar(min = 0, max = total_segments, style = 3)

for(i in 1:total_segments) {
  
  dat <- segment_results[[i]]
  res <- dat$res
  stop_a <- dat$start_m
  stop_b <- dat$end_m
  
  if(!is.na(res$dist_total_m)) {
    dist_val <- round(res$dist_total_m, 2)
    
    # Combine components (Network + any remaining Stubs)
    comp <- list()
    if(!is.null(res$seg_from)) comp[[1]] <- res$seg_from
    if(!is.null(res$net_route)) comp[[length(comp)+1]] <- res$net_route
    if(!is.null(res$seg_to)) comp[[length(comp)+1]] <- res$seg_to
    
    road_path <- if(length(comp) > 0) do.call(rbind, comp) else NULL
    
    # Save Stats
    final_stats <- rbind(final_stats, data.frame(
      Segment_ID = i,
      From = route_data$busstopname[i],
      To = route_data$busstopname[i+1],
      Distance_m = dist_val,
      Status = "✅ OK"
    ))
    
    # Save Map
    if(!is.null(road_path)) {
      m_single <- mapview(road_path, color = "blue", lwd = 5, 
                          layer.name = paste("Segment", i), label = paste(dist_val, "m")) +
        mapview(res$proj_from, col.regions = "cyan", cex = 6, layer.name = "Snap Start") +
        mapview(res$proj_to, col.regions = "magenta", cex = 6, layer.name = "Snap End") +
        mapview(rbind(stop_a, stop_b), col.regions = "red", cex = 3, layer.name = "Original GPS")
      
      map_list[[i]] <- m_single
    }
  } else {
    # Failed Segment
    final_stats <- rbind(final_stats, data.frame(
      Segment_ID = i, From = route_data$busstopname[i], To = route_data$busstopname[i+1],
      Distance_m = NA, Status = "❌ FAIL"
    ))
    map_list[[i]] <- NULL
  }
  setTxtProgressBar(pb_maps, i)
}
close(pb_maps)

print(final_stats)
message("✅ Done. Check map_list[[6]], map_list[[31]], map_list[[34]] to verify fixes.")

# Show the first map immediately
map_list[[16]]


# Initialize the counter (Run this once)
current_seg <- 1

# FUNCTION: Run this block repeatedly to see the next segment
print(map_list[[current_seg]])
current_seg <- current_seg + 1
print(map_list[[current_seg]])

