# --- 1. EXTRACT DATA ---
path_19_raw <- segment_results[[19]]$res$net_route
crs_native  <- st_crs(path_19_raw)

# Get Snap points (Cyan and Magenta)
start_pt    <- st_coordinates(segment_results[[19]]$res$proj_from)
end_pt      <- st_coordinates(segment_results[[19]]$res$proj_to)
full_coords <- st_coordinates(path_19_raw)

# --- 2. CONSTRUCT GEOMETRY ---
# Sequence: Start Snap -> V2 through the end of the road -> End Snap
new_coords_19 <- rbind(
  matrix(start_pt[1, 1:2], ncol = 2),                   # 1. Start Snap
  matrix(full_coords[2:nrow(full_coords), 1:2], ncol = 2), # 2. Skip V1, use V2 to End
  matrix(end_pt[1, 1:2], ncol = 2)                       # 3. End Snap
)

proposed_sf_19 <- st_sf(
  geometry = st_sfc(st_linestring(new_coords_19), crs = crs_native)
)

# --- 3. VISUALIZE ---
mapview(path_19_raw, color = "red", lwd = 1, layer.name = "Original V1 Hook") +
  mapview(proposed_sf_19, color = "cyan", lwd = 4, layer.name = "Corrected Seg 19") +
  mapview(segment_results[[19]]$res$proj_from, col.regions = "cyan", cex = 6) +
  mapview(segment_results[[19]]$res$proj_to, col.regions = "magenta", cex = 6)

# ==============================================================================
# PERMANENT COMMIT: SEGMENT 19 (START SNAP -> V2 BRIDGE -> ALL -> END SNAP)
# ==============================================================================

# 1. Access native CRS and coordinates
path_19_raw <- segment_results[[19]]$res$net_route
crs_native  <- st_crs(path_19_raw)

# Extract Snap points and existing vertex coordinates
start_pt    <- st_coordinates(segment_results[[19]]$res$proj_from)
end_pt      <- st_coordinates(segment_results[[19]]$res$proj_to)
full_coords <- st_coordinates(path_19_raw)

# 2. Build the optimized LINESTRING
# Sequence: Start Snap -> V2 through the VERY LAST vertex -> End Snap
new_coords_19 <- rbind(
