# ==============================================================================

library(sf)
library(mapview)

# --- 1. EXTRACT DATA ---
path_11_raw  <- segment_results[[11]]$res$net_route
crs_native   <- st_crs(path_11_raw)

# Get Snap points and existing vertex coordinates
start_pt    <- st_coordinates(segment_results[[11]]$res$proj_from)
end_pt      <- st_coordinates(segment_results[[11]]$res$proj_to)
full_coords <- st_coordinates(path_11_raw)

# --- 2. CONSTRUCT GEOMETRY ---
# Sequence: Start Snap -> V2 through the rest of the road -> End Snap
new_coords_11 <- rbind(
  matrix(start_pt[1, 1:2], ncol = 2),                    # 1. Start Snap
  matrix(full_coords[2:nrow(full_coords), 1:2], ncol = 2), # 2. Skip V1, follow V2 to End
  matrix(end_pt[1, 1:2], ncol = 2)                        # 3. End Snap
)

proposed_sf_11 <- st_sf(
  geometry = st_sfc(st_linestring(new_coords_11), crs = crs_native)
)

# --- 3. VISUALIZE ---
mapview(path_11_raw, color = "red", lwd = 1, layer.name = "Original Path (V1 Hook)") +
  mapview(proposed_sf_11, color = "cyan", lwd = 4, layer.name = "Corrected Seg 11") +
  mapview(segment_results[[11]]$res$proj_from, col.regions = "cyan", cex = 6, layer.name = "Start Snap") +
  mapview(segment_results[[11]]$res$proj_to, col.regions = "magenta", cex = 6, layer.name = "End Snap")

# ==============================================================================
# PERMANENT COMMIT: SEGMENT 11 (START SNAP -> V2 BRIDGE -> ALL -> END SNAP)
# ==============================================================================

# 1. Access native CRS and coordinates
path_11_raw  <- segment_results[[11]]$res$net_route
crs_native   <- st_crs(path_11_raw)

# Extract Snap points and existing vertex coordinates
start_pt    <- st_coordinates(segment_results[[11]]$res$proj_from)
end_pt      <- st_coordinates(segment_results[[11]]$res$proj_to)
full_coords <- st_coordinates(path_11_raw)

# 2. Build the optimized LINESTRING
# Sequence: Start Snap -> V2 through the VERY LAST vertex -> End Snap
new_coords_11 <- rbind(
  matrix(start_pt[1, 1:2], ncol = 2),                    # 1. Start Snap
  matrix(full_coords[2:nrow(full_coords), 1:2], ncol = 2), # 2. V2 to the end of road
  matrix(end_pt[1, 1:2], ncol = 2)                        # 3. End Snap
)

# 3. Update the segment_results list with clean SF structure
segment_results[[11]]$res$net_route <- st_sf(
  geometry = st_sfc(st_linestring(new_coords_11), crs = crs_native)
)

# 4. Update the total distance field
segment_results[[11]]$res$dist_total_m <- as.numeric(st_length(segment_results[[11]]$res$net_route))

