library(sf)
library(dplyr)
library(mapview)
library(leaflet)
library(htmlwidgets)

# !!! TYPE YOUR ROUTE NUMBER HERE !!!
MANUAL_ROUTE_NUM <- "910"   # <--- Change "9" to "8", "10", etc.

message(paste("🔗 Processing Route:", MANUAL_ROUTE_NUM))

# 1. EXTRACT GEOMETRIES
geom_list <- list()
if(exists("segment_results")) {
  for(i in 1:length(segment_results)) {
    res <- segment_results[[i]]$res
    if(!is.null(res$seg_from))  geom_list[[length(geom_list) + 1]] <- st_geometry(res$seg_from)
    if(!is.null(res$net_route)) geom_list[[length(geom_list) + 1]] <- st_geometry(res$net_route)
    if(!is.null(res$seg_to))    geom_list[[length(geom_list) + 1]] <- st_geometry(res$seg_to)
  }
} else {
  stop("❌ 'segment_results' not found.")
}

# 2. MERGE INTO ONE LINE
combined_sfc <- do.call(c, geom_list)
full_route_union <- st_union(combined_sfc)
full_route_sf <- st_sf(geometry = full_route_union)
st_crs(full_route_sf) <- st_crs(geom_list[[1]]) 

# 3. USE MANUAL ROUTE NUMBER
clean_route_num <- gsub("[^A-Za-z0-9_-]", "", MANUAL_ROUTE_NUM)
filename <- paste0("Route_", clean_route_num, "_Final_Continuous.html")
outpath <- file.path(getwd(), filename)

message(paste("🌍 Generating Map..."))

# 4. GENERATE MAP
m <- mapview(route_data, 
             col.regions = "red", 
             cex = 4, 
             layer.name = paste("Stops - Route", clean_route_num),
             label = paste0(route_data$ordering, ". ", route_data$busstopname)) +
  mapview(full_route_sf, 
          color = "blue", 
          lwd = 6, 
          alpha = 0.7,
          layer.name = paste("Path - Route", clean_route_num))

# 5. SAVE
tryCatch({
  htmlwidgets::saveWidget(m@map, file = outpath, selfcontained = TRUE)
  message(paste0("✅ SUCCESS! Saved to: ", outpath))
}, error = function(e) {
  message("❌ Save failed (Check if file is open). Map displayed below.")
})

m

