library(sf)
library(mapview)

# List of segments to inspect
inspect_segs <- c(6, 7, 8, 10)

for (idx in inspect_segs) {
  
  # 1. Extract Data
  res_data    <- segment_results[[idx]]$res
  path_raw    <- res_data$net_route
  crs_native  <- st_crs(path_raw)
  
  # Extract specific coordinates
  snap_start  <- res_data$proj_from
  snap_end    <- res_data$proj_to
  full_coords <- st_coordinates(path_raw)
  
  # 2. Build V2-Bridged Geometry
  # Sequence: Start Snap -> Vertex 2 through End -> End Snap
  new_coords <- rbind(
    matrix(st_coordinates(snap_start)[1, 1:2], ncol = 2),
    matrix(full_coords[2:nrow(full_coords), 1:2], ncol = 2),
    matrix(st_coordinates(snap_end)[1, 1:2], ncol = 2)
  )
  
  new_seg_sf <- st_sf(
    geometry = st_sfc(st_linestring(new_coords), crs = crs_native)
  )
  
  # 3. Create Map
  m <- mapview(path_raw, color = "red", lwd = 1, lty = 2, layer.name = paste("Old Seg", idx)) +
    mapview(new_seg_sf, color = "cyan", lwd = 4, layer.name = paste("FIXED Seg", idx)) +
    mapview(snap_start, col.regions = "cyan", color = "white", cex = 7, layer.name = "START SNAP") +
    mapview(snap_end, col.regions = "magenta", color = "white", cex = 7, layer.name = "END SNAP")
  
  # Print to viewer (use arrows to switch between maps)
  print(m)
  
  message(paste("Previewing Segment", idx))
}

