crs_native  <- st_crs(path_raw)

start_pt    <- st_coordinates(res_data$proj_from)
end_pt      <- st_coordinates(res_data$proj_to)
full_coords <- st_coordinates(path_raw)

# Sequence: Start Snap -> V2 through the rest of the road -> End Snap
new_coords_22 <- rbind(
  matrix(start_pt[1, 1:2], ncol = 2),
  matrix(full_coords[2:nrow(full_coords), 1:2], ncol = 2),
  matrix(end_pt[1, 1:2], ncol = 2)
)

preview_sf_22 <- st_sf(geometry = st_sfc(st_linestring(new_coords_22), crs = crs_native))

mapview(path_raw, color = "red", lwd = 1, lty = 2, layer.name = "Original Hook") +
  mapview(preview_sf_22, color = "cyan", lwd = 4, layer.name = "V2 Fixed Path") +
  mapview(res_data$proj_from, col.regions = "cyan", cex = 7) +
  mapview(res_data$proj_to, col.regions = "magenta", cex = 7)

# ==============================================================================
# PERMANENT COMMIT: SEGMENT 22 (START SNAP -> V2 BRIDGE -> ALL -> END SNAP)
# ==============================================================================

# 1. Access native CRS and coordinates
path_22_raw  <- segment_results[[22]]$res$net_route
crs_native   <- st_crs(path_22_raw)

# Extract Snap points and existing vertex coordinates
start_pt    <- st_coordinates(segment_results[[22]]$res$proj_from)
end_pt      <- st_coordinates(segment_results[[22]]$res$proj_to)
full_coords <- st_coordinates(path_22_raw)

# 2. Build the optimized LINESTRING
# Sequence: Start Snap -> V2 through the VERY LAST vertex -> End Snap
new_coords_22 <- rbind(
  matrix(start_pt[1, 1:2], ncol = 2),                    # 1. Start Snap
  matrix(full_coords[2:nrow(full_coords), 1:2], ncol = 2), # 2. V2 to the end of road
  matrix(end_pt[1, 1:2], ncol = 2)                        # 3. End Snap
)

# 3. Update the segment_results list with clean SF structure
segment_results[[22]]$res$net_route <- st_sf(
  geometry = st_sfc(st_linestring(new_coords_22), crs = crs_native)
)

# 4. Update the total distance field
segment_results[[22]]$res$dist_total_m <- as.numeric(st_length(segment_results[[22]]$res$net_route))

# 5. Clean up leftover metadata
segment_results[[22]]$res$seg_from <- NULL
segment_results[[22]]$res$seg_to   <- NULL

