# 1. SETUP & SELECTION
rm(route_data) # <--- ADD THIS LINE! Deletes the old Route data
target_route_id <- "932"
code_seq <- master_route_codes[[target_route_id]]

# Build Route Data
stops_db <- bus_proj %>%
  filter(busstopcode %in% code_seq) %>%
  distinct(busstopcode, .keep_all=TRUE)

seq_table <- tibble(ordering=1:length(code_seq), busstopcode=code_seq)
route_data <- seq_table %>%
  left_join(stops_db, by="busstopcode") %>%
  arrange(ordering) %>%
  st_as_sf()

message(paste0("🚀 Processing Route ", target_route_id, ": ", nrow(route_data), " Stops..."))

# 2. INITIALIZE STORAGE (CRITICAL STEP)
segment_results <- list() 
results_df <- data.frame()
total_segments <- nrow(route_data) - 1

# 3. MAIN CALCULATION LOOP
message("🔄 Running initial path calculations...")
pb <- txtProgressBar(min = 0, max = total_segments, style = 3)

for(i in 1:total_segments) {
  start_pt <- route_data[i, ]
  end_pt   <- route_data[i+1, ]
  start_m  <- st_transform(start_pt, target_crs)
  end_m    <- st_transform(end_pt, target_crs)
  
  # Calculate Route
  res <- edge_shortest_route_between_projections_dir(start_m, end_m)
  
  # SAVE RAW DATA into the list so we can modify it later
  segment_results[[i]] <- list(
    res = res,
    start_m = start_m,
    end_m = end_m
  )
  
  setTxtProgressBar(pb, i)
}
close(pb)

# ==============================================================================
# Preview SEGMENT 7 (SKIP V1) & SEGMENT 19 (STRAIGHT)
# ==============================================================================

library(sf)
library(mapview)

# --- 1. PREVIEW SEGMENT 7 (SKIP V1 / V2 BRIDGE) ---
res_7        <- segment_results[[7]]$res
path_7_raw   <- res_7$net_route
crs_7        <- st_crs(path_7_raw)
full_coords_7 <- st_coordinates(path_7_raw)

# Logic: Start Snap -> Jump to V2 -> Follow road to end
bridge_coords_7 <- rbind(
  matrix(st_coordinates(res_7$proj_from)[1, 1:2], ncol = 2),
  matrix(full_coords_7[2:nrow(full_coords_7), 1:2], ncol = 2),
  matrix(st_coordinates(res_7$proj_to)[1, 1:2], ncol = 2)
)

sf_7_fixed <- st_sf(geometry = st_sfc(st_linestring(bridge_coords_7), crs = crs_7))

map_7 <- mapview(path_7_raw, color = "red", lwd = 1, lty = 2, layer.name = "Original Hook (7)") +
  mapview(sf_7_fixed, color = "cyan", lwd = 4, layer.name = "Skip Fix (7)") +
  mapview(res_7$proj_from, col.regions = "cyan", cex = 7) +
  mapview(res_7$proj_to, col.regions = "magenta", cex = 7)

# --- 2. PREVIEW SEGMENT 19 (STRAIGHT LINE / DIRECT BRIDGE) ---
res_19       <- segment_results[[19]]$res
path_19_raw  <- res_19$net_route
crs_19       <- st_crs(path_19_raw)

# Logic: Start Snap -> End Snap (2 points only)
straight_coords_19 <- rbind(
  matrix(st_coordinates(res_19$proj_from)[1, 1:2], ncol = 2),
  matrix(st_coordinates(res_19$proj_to)[1, 1:2], ncol = 2)
)

sf_19_fixed <- st_sf(geometry = st_sfc(st_linestring(straight_coords_19), crs = crs_19))

map_19 <- mapview(path_19_raw, color = "red", lwd = 1, lty = 2, layer.name = "Original Detour (19)") +
  mapview(sf_19_fixed, color = "green", lwd = 5, layer.name = "Straight Fix (19)") +
  mapview(res_19$proj_from, col.regions = "cyan", cex = 7) +
  mapview(res_19$proj_to, col.regions = "magenta", cex = 7)

# Display both
print(map_7)
print(map_19)

# ==============================================================================
# BATCH COMMIT: SEGMENT 7 (SKIP V1) & SEGMENT 19 (STRAIGHT)
# ==============================================================================

# --- 1. COMMIT SEGMENT 7 (V2 BRIDGE / SKIP V1) ---
res_7        <- segment_results[[7]]$res
path_7_raw   <- res_7$net_route
crs_7        <- st_crs(path_7_raw)
full_coords_7 <- st_coordinates(path_7_raw)

# Construct bridge: Start Snap -> V2 to End -> End Snap
coords_7 <- rbind(
  matrix(st_coordinates(res_7$proj_from)[1, 1:2], ncol = 2),
  matrix(full_coords_7[2:nrow(full_coords_7), 1:2], ncol = 2),
  matrix(st_coordinates(res_7$proj_to)[1, 1:2], ncol = 2)
)

segment_results[[7]]$res$net_route <- st_sf(
  geometry = st_sfc(st_linestring(coords_7), crs = crs_7)
)
segment_results[[7]]$res$dist_total_m <- as.numeric(st_length(segment_results[[7]]$res$net_route))

message(paste0("✅ Segment 7 Finalized (Skip V1): ", round(segment_results[[7]]$res$dist_total_m, 2), "m"))


# --- 2. COMMIT SEGMENT 19 (DIRECT STRAIGHT LINE) ---
res_19       <- segment_results[[19]]$res
crs_19       <- st_crs(res_19$net_route)

# Construct 2-point straight line
coords_19 <- rbind(
  matrix(st_coordinates(res_19$proj_from)[1, 1:2], ncol = 2),
  matrix(st_coordinates(res_19$proj_to)[1, 1:2], ncol = 2)
)

segment_results[[19]]$res$net_route <- st_sf(
  geometry = st_sfc(st_linestring(coords_19), crs = crs_19)
)
segment_results[[19]]$res$dist_total_m <- as.numeric(st_length(segment_results[[19]]$res$net_route))

message(paste0("✅ Segment 19 Finalized (Straight): ", round(segment_results[[19]]$res$dist_total_m, 2), "m"))

# Clean up helper metadata for both
segment_results[[7]]$res$seg_from <- segment_results[[7]]$res$seg_to <- NULL
segment_results[[19]]$res$seg_from <- segment_results[[19]]$res$seg_to <- NULL

# ==============================================================================
# 5. GENERATE FINAL MAPS & STATS
# ==============================================================================
map_list <- list()
final_stats <- data.frame()

message("🎨 Generating maps...")
pb_maps <- txtProgressBar(min = 0, max = total_segments, style = 3)

for(i in 1:total_segments) {
  
  dat <- segment_results[[i]]
  res <- dat$res
  stop_a <- dat$start_m
  stop_b <- dat$end_m
  
  if(!is.na(res$dist_total_m)) {
    dist_val <- round(res$dist_total_m, 2)
    
    # Combine components (Network + any remaining Stubs)
    comp <- list()
    if(!is.null(res$seg_from)) comp[[1]] <- res$seg_from
    if(!is.null(res$net_route)) comp[[length(comp)+1]] <- res$net_route
    if(!is.null(res$seg_to)) comp[[length(comp)+1]] <- res$seg_to
    
    road_path <- if(length(comp) > 0) do.call(rbind, comp) else NULL
    
    # Save Stats
    final_stats <- rbind(final_stats, data.frame(
      Segment_ID = i,
      From = route_data$busstopname[i],
      To = route_data$busstopname[i+1],
      Distance_m = dist_val,
      Status = "✅ OK"
    ))
    
    # Save Map
    if(!is.null(road_path)) {
      m_single <- mapview(road_path, color = "blue", lwd = 5, 
                          layer.name = paste("Segment", i), label = paste(dist_val, "m")) +
        mapview(res$proj_from, col.regions = "cyan", cex = 6, layer.name = "Snap Start") +
        mapview(res$proj_to, col.regions = "magenta", cex = 6, layer.name = "Snap End") +
        mapview(rbind(stop_a, stop_b), col.regions = "red", cex = 3, layer.name = "Original GPS")
      
      map_list[[i]] <- m_single
    }
  } else {
    # Failed Segment
    final_stats <- rbind(final_stats, data.frame(
      Segment_ID = i, From = route_data$busstopname[i], To = route_data$busstopname[i+1],
      Distance_m = NA, Status = "❌ FAIL"
    ))
    map_list[[i]] <- NULL
  }
  setTxtProgressBar(pb_maps, i)
}
close(pb_maps)

print(final_stats)
message("✅ Done. Check map_list[[6]], map_list[[31]], map_list[[34]] to verify fixes.")

