# ==============================================================================
# Preview SEGMENTS 16 & 22 (SKIP V1) + SEGMENT 31 (STRAIGHT)
# ==============================================================================

library(sf)
library(mapview)

# --- 1. PREVIEW SEGMENTS 16 & 22 (SKIP V1 / V2 BRIDGE) ---
inspect_skip <- c(16, 22)

for (idx in inspect_skip) {
  res_skip    <- segment_results[[idx]]$res
  path_raw    <- res_skip$net_route
  full_coords <- st_coordinates(path_raw)
  crs_native  <- st_crs(path_raw)
  
  # Logic: Start Snap -> Jump to V2 -> Follow road to end
  bridge_coords <- rbind(
    matrix(st_coordinates(res_skip$proj_from)[1, 1:2], ncol = 2),
    matrix(full_coords[2:nrow(full_coords), 1:2], ncol = 2),
    matrix(st_coordinates(res_skip$proj_to)[1, 1:2], ncol = 2)
  )
  
  sf_fixed <- st_sf(geometry = st_sfc(st_linestring(bridge_coords), crs = crs_native))
  
  m_skip <- mapview(path_raw, color = "red", lwd = 1, lty = 2, layer.name = paste("Original Hook", idx)) +
    mapview(sf_fixed, color = "cyan", lwd = 4, layer.name = paste("Skip Fix", idx)) +
    mapview(res_skip$proj_from, col.regions = "cyan", cex = 7) +
    mapview(res_skip$proj_to, col.regions = "magenta", cex = 7)
  print(m_skip)
}

# --- 2. PREVIEW SEGMENT 31 (STRAIGHT LINE / DIRECT BRIDGE) ---
res_31       <- segment_results[[31]]$res
crs_31       <- st_crs(res_31$net_route)

# Logic: Start Snap -> End Snap (Direct vector)
straight_coords_31 <- rbind(
  matrix(st_coordinates(res_31$proj_from)[1, 1:2], ncol = 2),
  matrix(st_coordinates(res_31$proj_to)[1, 1:2], ncol = 2)
)

sf_31_fixed <- st_sf(geometry = st_sfc(st_linestring(straight_coords_31), crs = crs_31))

m_31 <- mapview(res_31$net_route, color = "red", lwd = 1, lty = 2, layer.name = "Original Detour (31)") +
  mapview(sf_31_fixed, color = "green", lwd = 5, layer.name = "Straight Fix (31)") +
  mapview(res_31$proj_from, col.regions = "cyan", cex = 7) +
  mapview(res_31$proj_to, col.regions = "magenta", cex = 7)

print(m_31)

# ==============================================================================
# BATCH COMMIT: SEGMENTS 16 & 22 (SKIP V1) + SEGMENT 31 (STRAIGHT)
# ==============================================================================

# --- 1. COMMIT SEGMENTS 16 & 22 (V2 BRIDGE / SKIP V1) ---
target_skip <- c(16, 22)

for (idx in target_skip) {
  res_data    <- segment_results[[idx]]$res
  path_raw    <- res_data$net_route
  crs_native  <- st_crs(path_raw)
  full_coords <- st_coordinates(path_raw)
  
  # Construct bridge: Start Snap -> V2 through End -> End Snap
  new_coords <- rbind(
    matrix(st_coordinates(res_data$proj_from)[1, 1:2], ncol = 2),
    matrix(full_coords[2:nrow(full_coords), 1:2], ncol = 2),
    matrix(st_coordinates(res_data$proj_to)[1, 1:2], ncol = 2)
  )
  
  segment_results[[idx]]$res$net_route <- st_sf(
    geometry = st_sfc(st_linestring(new_coords), crs = crs_native)
  )
  segment_results[[idx]]$res$dist_total_m <- as.numeric(st_length(segment_results[[idx]]$res$net_route))
  
  message(paste0("✅ Segment ", idx, " Finalized (Skip V1): ", 
                 round(segment_results[[idx]]$res$dist_total_m, 2), "m"))
}

# --- 2. COMMIT SEGMENT 31 (DIRECT STRAIGHT LINE) ---
res_31      <- segment_results[[31]]$res
crs_31      <- st_crs(res_31$net_route)

# Construct 2-point straight line
coords_31 <- rbind(
  matrix(st_coordinates(res_31$proj_from)[1, 1:2], ncol = 2),
  matrix(st_coordinates(res_31$proj_to)[1, 1:2], ncol = 2)
)

segment_results[[31]]$res$net_route <- st_sf(
  geometry = st_sfc(st_linestring(coords_31), crs = crs_31)
)
segment_results[[31]]$res$dist_total_m <- as.numeric(st_length(segment_results[[31]]$res$net_route))

message(paste0("✅ Segment 31 Finalized (Straight): ", 
               round(segment_results[[31]]$res$dist_total_m, 2), "m"))

# --- 3. CLEANUP METADATA ---
for (i in c(16, 22, 31)) {
  segment_results[[i]]$res$seg_from <- segment_results[[i]]$res$seg_to <- NULL
}

# ==============================================================================
# 5. GENERATE FINAL MAPS & STATS
# ==============================================================================
