end_pt      <- st_coordinates(res_6$proj_to)

# 3. Construct the Straight Line Geometry
# Logic: Point A to Point B only (Ignoring routing engine's road nodes)
straight_coords_6 <- rbind(
  matrix(start_pt[1, 1:2], ncol = 2),
  matrix(end_pt[1, 1:2], ncol = 2)
)

# 4. Update the segment_results list
segment_results[[6]]$res$net_route <- st_sf(
  geometry = st_sfc(st_linestring(straight_coords_6), crs = crs_native)
)

