    mapview(sf_straight, color = "green", lwd = 5, layer.name = paste("Straight Fix", idx)) +
    mapview(res_data$proj_from, col.regions = "cyan", color = "white", cex = 7, layer.name = "START SNAP") +
    mapview(res_data$proj_to, col.regions = "magenta", color = "white", cex = 7, layer.name = "END SNAP")
  
