    f2 <- as.numeric(sf::st_line_project(raw_path, p2, normalized = TRUE))
    
    preview_6 <- lwgeom::st_linesubstring(raw_path, min(f1, f2), max(f1, f2)) %>%
      st_sf(geometry=., crs=target_crs)
    
