  # 5. Build the Final Geometry
  # Sequence: Start -> V2 -> V3 -> V4 -> V5 -> V6 -> End
  new_coords <- rbind(p_start, selected_vertices, p_end)
  
  manual_path <- st_linestring(new_coords) %>%
