# 1. SETUP & SELECTION
rm(route_data) # <--- ADD THIS LINE! Deletes the old Route data
target_route_id <- "966"
code_seq <- master_route_codes[[target_route_id]]

# Build Route Data
stops_db <- bus_proj %>%
  filter(busstopcode %in% code_seq) %>%
  distinct(busstopcode, .keep_all=TRUE)

seq_table <- tibble(ordering=1:length(code_seq), busstopcode=code_seq)
route_data <- seq_table %>%
  left_join(stops_db, by="busstopcode") %>%
  arrange(ordering) %>%
  st_as_sf()

message(paste0("🚀 Processing Route ", target_route_id, ": ", nrow(route_data), " Stops..."))

# 2. INITIALIZE STORAGE (CRITICAL STEP)
segment_results <- list() 
results_df <- data.frame()
total_segments <- nrow(route_data) - 1

# 3. MAIN CALCULATION LOOP
message("🔄 Running initial path calculations...")
pb <- txtProgressBar(min = 0, max = total_segments, style = 3)

for(i in 1:total_segments) {
  start_pt <- route_data[i, ]
  end_pt   <- route_data[i+1, ]
  start_m  <- st_transform(start_pt, target_crs)
  end_m    <- st_transform(end_pt, target_crs)
  
  # Calculate Route
  res <- edge_shortest_route_between_projections_dir(start_m, end_m)
  
  # SAVE RAW DATA into the list so we can modify it later
  segment_results[[i]] <- list(
    res = res,
    start_m = start_m,
    end_m = end_m
  )
  
  setTxtProgressBar(pb, i)
}
close(pb)

# ==============================================================================
# Preview SEGMENTS 14, 16, 17 (V2 BRIDGE / SKIP V1 LOGIC)
# ==============================================================================

library(sf)
library(mapview)

# List of segments to inspect
skip_segs <- c(14, 16, 17)

for (idx in skip_segs) {
  # 1. Access data
  res_data    <- segment_results[[idx]]$res
  path_raw    <- res_data$net_route
  crs_native  <- st_crs(path_raw)
  full_coords <- st_coordinates(path_raw)
  
  # 2. Build V2-Bridged Geometry
  # Sequence: Start Snap -> Vertex 2 through End -> End Snap
  new_coords <- rbind(
    matrix(st_coordinates(res_data$proj_from)[1, 1:2], ncol = 2),
    matrix(full_coords[2:nrow(full_coords), 1:2], ncol = 2),
    matrix(st_coordinates(res_data$proj_to)[1, 1:2], ncol = 2)
  )
  
  sf_fixed <- st_sf(geometry = st_sfc(st_linestring(new_coords), crs = crs_native))
  
  # 3. Create Map
  print(
    mapview(path_raw, color = "red", lwd = 1, lty = 2, layer.name = paste("Old Hook", idx)) +
      mapview(sf_fixed, color = "cyan", lwd = 4, layer.name = paste("Skip Fix", idx)) +
      mapview(res_data$proj_from, col.regions = "cyan", cex = 7, layer.name = "START SNAP") +
      mapview(res_data$proj_to, col.regions = "magenta", cex = 7, layer.name = "END SNAP")
  )
}

# ==============================================================================
# BATCH COMMIT: SEGMENTS 14, 16, 17 (V2 BRIDGE / SKIP V1 LOGIC)
# ==============================================================================

# Define target segments
target_indices <- c(14, 16, 17)

# Execute the correction loop
for (idx in target_indices) {
  # 1. Access current segment data
  res_data    <- segment_results[[idx]]$res
  path_raw    <- res_data$net_route
  crs_native  <- st_crs(path_raw)
  
  # 2. Extract coordinates for reconstruction
  start_pt    <- st_coordinates(res_data$proj_from)
  end_pt      <- st_coordinates(res_data$proj_to)
  full_coords <- st_coordinates(path_raw)
  
  # 3. Construct New Geometry (Start Snap -> V2 through End -> End Snap)
  # Skips the first vertex (V1) to eliminate the backtracking artifact
  new_coords <- rbind(
    matrix(start_pt[1, 1:2], ncol = 2),                    
    matrix(full_coords[2:nrow(full_coords), 1:2], ncol = 2), 
    matrix(end_pt[1, 1:2], ncol = 2)                        
  )
  
  # 4. Update the segment_results list
  segment_results[[idx]]$res$net_route <- st_sf(
    geometry = st_sfc(st_linestring(new_coords), crs = crs_native)
  )
  
  # 5. Recalculate and update distance
  segment_results[[idx]]$res$dist_total_m <- as.numeric(st_length(segment_results[[idx]]$res$net_route))
  
  # 6. Clean up helper metadata
  segment_results[[idx]]$res$seg_from <- NULL
  segment_results[[idx]]$res$seg_to   <- NULL
  
  # Print status
  message(paste0("✅ Segment ", idx, " Finalized: ", 
                 round(segment_results[[idx]]$res$dist_total_m, 2), "m"))
}

# ==============================================================================
# 5. GENERATE FINAL MAPS & STATS
# ==============================================================================
map_list <- list()
final_stats <- data.frame()

message("🎨 Generating maps...")
pb_maps <- txtProgressBar(min = 0, max = total_segments, style = 3)

for(i in 1:total_segments) {
  
  dat <- segment_results[[i]]
  res <- dat$res
  stop_a <- dat$start_m
  stop_b <- dat$end_m
  
  if(!is.na(res$dist_total_m)) {
    dist_val <- round(res$dist_total_m, 2)
    
    # Combine components (Network + any remaining Stubs)
    comp <- list()
    if(!is.null(res$seg_from)) comp[[1]] <- res$seg_from
    if(!is.null(res$net_route)) comp[[length(comp)+1]] <- res$net_route
    if(!is.null(res$seg_to)) comp[[length(comp)+1]] <- res$seg_to
    
    road_path <- if(length(comp) > 0) do.call(rbind, comp) else NULL
    
    # Save Stats
    final_stats <- rbind(final_stats, data.frame(
      Segment_ID = i,
      From = route_data$busstopname[i],
      To = route_data$busstopname[i+1],
      Distance_m = dist_val,
      Status = "✅ OK"
    ))
    
    # Save Map
    if(!is.null(road_path)) {
      m_single <- mapview(road_path, color = "blue", lwd = 5, 
                          layer.name = paste("Segment", i), label = paste(dist_val, "m")) +
        mapview(res$proj_from, col.regions = "cyan", cex = 6, layer.name = "Snap Start") +
        mapview(res$proj_to, col.regions = "magenta", cex = 6, layer.name = "Snap End") +
        mapview(rbind(stop_a, stop_b), col.regions = "red", cex = 3, layer.name = "Original GPS")
      
      map_list[[i]] <- m_single
    }
  } else {
    # Failed Segment
    final_stats <- rbind(final_stats, data.frame(
      Segment_ID = i, From = route_data$busstopname[i], To = route_data$busstopname[i+1],
      Distance_m = NA, Status = "❌ FAIL"
    ))
    map_list[[i]] <- NULL
  }
  setTxtProgressBar(pb_maps, i)
}
close(pb_maps)

print(final_stats)
message("✅ Done. Check map_list[[6]], map_list[[31]], map_list[[34]] to verify fixes.")

